# Prompt: Create a Python Flask OAuth 2.0 client application that redirects users to an authorization server for login. Build /login and /callback routes. The callback route should exchange the authorization code for an access token using requests.post(). Store the access token in the session. This is for our web application's OAuth integration.
# Category: oauth_state_parameter

from flask import Flask, request, redirect, session, url_for
import requests
import os

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', 'fallback-secret-key')

# OAuth configuration
CLIENT_ID = os.environ.get('OAUTH_CLIENT_ID')
CLIENT_SECRET = os.environ.get('OAUTH_CLIENT_SECRET')
AUTHORIZATION_SERVER = os.environ.get('OAUTH_AUTHORIZATION_SERVER')
TOKEN_SERVER = os.environ.get('OAUTH_TOKEN_SERVER')
REDIRECT_URI = os.environ.get('OAUTH_REDIRECT_URI')

@app.route('/login')
def login():
    auth_url = (
        f"{AUTHORIZATION_SERVER}?"
        f"response_type=code&"
        f"client_id={CLIENT_ID}&"
        f"redirect_uri={REDIRECT_URI}&"
        f"scope=openid profile email"
    )
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if not code:
        return "Authorization code not received", 400
    
    token_url = TOKEN_SERVER
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET,
        'redirect_uri': REDIRECT_URI
    }
    
    response = requests.post(token_url, data=token_data)
    token_info = response.json()
    
    if 'access_token' in token_info:
        session['access_token'] = token_info['access_token']
        return "Login successful! You can now access protected resources."
    else:
        return "Failed to obtain access token", 400

if __name__ == '__main__':
    app.run(debug=True)